#include <iostream>

// The function to be tested
int incrementPointerValue(int* ptr) {
    int oldValue = *ptr;
    *ptr = oldValue + 5;
    return oldValue + 5;
}

int main() {
    std::cout << "Running test cases for Readability / Efficiency Issue...\n";

    int myValue = 20;
    std::cout << "Original value: " << myValue << std::endl;
    int newValue = incrementPointerValue(&myValue);
    std::cout << "Value after increment: " << myValue << std::endl;
    std::cout << "Returned new value: " << newValue << std::endl;

    std::cout << "\n";

    int anotherValue = -3;
    std::cout << "Original value: " << anotherValue << std::endl;
    newValue = incrementPointerValue(&anotherValue);
    std::cout << "Value after increment: " << anotherValue << std::endl;
    std::cout << "Returned new value: " << newValue << std::endl;

    return 0;
}
